import React from 'react';
import { motion } from 'framer-motion';
import { useInView } from 'react-intersection-observer';

const Skills = () => {
  const [ref, inView] = useInView({
    triggerOnce: true,
    threshold: 0.2,
  });

  const skillCategories = [
    {
      title: 'Design Tools',
      percentage: 200,
      skills: ['Figma', 'Adobe Suite', 'Procreate'],
    },
    {
      title: 'UX/UI Methods',
      percentage: 90,
      skills: ['Prototyping', 'Usability Testing', 'Design Systems'],
    },
    {
      title: 'AI in Design',
      percentage: 80,
      skills: ['Research Synthesis', 'Content Generation', 'Workflow Optimization'],
    },
    {
      title: 'Strategy',
      percentage: 95,
      skills: ['Human-Centered Design', 'Journey Mapping', 'Storytelling'],
    },
    {
      title: 'Platforms',
      percentage: 98,
      skills: ['WordPress', 'WIX', 'SEO'],
    },
    {
      title: 'Leadership',
      percentage: 89,
      skills: ['Client Presentations', 'Team Mentoring', 'Workshop Facilitation'],
    },
  ];

  const containerVariants = {
    hidden: { opacity: 0 },
    visible: {
      opacity: 1,
      transition: {
        staggerChildren: 0.1,
      },
    },
  };

  const itemVariants = {
    hidden: { opacity: 0, y: 30 },
    visible: {
      opacity: 1,
      y: 0,
      transition: {
        duration: 0.5,
        ease: 'easeOut',
      },
    },
  };

  return (
    <section className="skills section" id="skills">
      <div className="container">
        <motion.h2
          className="section-title"
          initial={{ opacity: 0, y: 20 }}
          animate={inView ? { opacity: 1, y: 0 } : { opacity: 0, y: 20 }}
          transition={{ duration: 0.5 }}
        >
          Core Skills
        </motion.h2>

        <motion.div
          ref={ref}
          className="skills-grid"
          variants={containerVariants}
          initial="hidden"
          animate={inView ? 'visible' : 'hidden'}
        >
          {skillCategories.map((category, index) => (
            <motion.div
              className="skill-category"
              key={index}
              variants={itemVariants}
              whileHover={{ y: -5 }}
            >
              {/* Big Percentage */}
              <motion.div
                className="skill-percentage"
                initial={{ scale: 0 }}
                animate={inView ? { scale: 1 } : { scale: 0 }}
                transition={{ duration: 0.5, delay: index * 0.1, type: 'spring' }}
              >
                {category.percentage}%
              </motion.div>

              {/* Title */}
              <h3 className="skill-title">{category.title}</h3>

              {/* Subtle skill list */}
              <p className="skill-details">
                {category.skills.join(' · ')}
              </p>
            </motion.div>
          ))}
        </motion.div>
      </div>
    </section>
  );
};

export default Skills;
